from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    parts: list[str] = []

    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # simple lexical mapping for common artist predicates
        if p == "birthDate":
            phrase = f"{s} was born on {o}"
        elif p == "birthYear":
            phrase = f"{s} was born in {o}"
        elif p == "birthPlace":
            phrase = f"{s} was born in {o}"
        elif p == "deathDate":
            phrase = f"{s} died on {o}"
        elif p == "deathPlace":
            phrase = f"{s} died in {o}"
        elif p == "origin":
            phrase = f"{s} originates from {o}"
        elif p == "genre":
            phrase = f"{s} is known for {o} music"
        elif p == "instrument":
            phrase = f"{s} plays {o}"
        elif p == "occupation":
            phrase = f"{s} is a {o}"
        elif p == "associatedBand/associatedMusicalArtist":
            phrase = f"{s} is associated with {o}"
        elif p == "recordLabel":
            phrase = f"{s} is signed to {o}"
        elif p == "activeYearsStartYear":
            phrase = f"{s} started their career in {o}"
        elif p == "activeYearsEndYear":
            phrase = f"{s} ended their career in {o}"
        elif p == "nationality":
            phrase = f"{s} is {o}"
        elif p == "capital":
            phrase = f"The capital of {s} is {o}"
        elif p == "country":
            phrase = f"{s} is in the country of {o}"
        elif p == "isPartOf":
            phrase = f"{s} is part of {o}"
        elif p in {"language", "officialLanguage"}:
            phrase = f"The language of {s} is {o}"
        else:
            # fallback generic phrasing
            phrase = f"{s} {p} {o}"

        parts.append(phrase)

    # Combine parts into a single fluent sentence
    if len(parts) == 1:
        return parts[0] + "."
    else:
        return ", ".join(parts[:-1]) + ", and " + parts[-1] + "."

